import React, { useEffect } from 'react'
import './styles.css'
import useProgressBarStore from './useProgressBarStore'
import ProgressBar from './ProgressBar'

function ProgressBars() {
    const { progressBars, addProgressBar } = useProgressBarStore((state) => state)
    function handleAdd() {
        addProgressBar({ id: progressBars.length, completed: false })
    }
    return (
        <>
            <div>
                {progressBars.map(pb => {
                    return (<ProgressBar key={pb.id} />)
                })}
            </div>
            <button onClick={handleAdd}>+Add</button>
        </>
    )
}

export default ProgressBars
